import { IMessageComposer } from '@nitrots/nitro-renderer';

export class HighLowLeaveComposer implements IMessageComposer<Array<any>> {
    private _data: Array<any>;

    constructor() {
        this._data = [];
    }

    public getMessageArray(): Array<any> {
        return this._data;
    }

    public dispose(): void {
        this._data = [];
    }
}
